data "aws_secretsmanager_secret_version" "creds" {
  secret_id = "rabbit_credentials"
}

data "terraform_remote_state" "rabbit" {
  backend = "s3"
  config = {
    bucket = var.terraform_state_s3_bucket_name
    key    = "aws/${var.aws_region}/mq.tfstate"
    region = var.aws_region
  }
}

data "aws_kms_key" "wrapidity_key" {
  key_id = "alias/wrapidity"
}

module "huntsman_globals" {
  source  = "app.terraform.io/meltwater/wrapidity-deployment/kubernetes//modules/htns-staging"
  version = "1.0.3"
}

data "aws_kms_secrets" "rabbit_secrets" {
  secret {
    name    = "password"
    payload = var.rabbit_password_encrypted
  }
}

data "aws_kms_secrets" "karma_language_secrets" {
